def drop_outlier_iqr(df, cols, k=1.5):
    """
    Drop outlier rows using IQR method (fit on given df).
    Print before-after statistics.

    Parameters
    ----------
    df : pd.DataFrame
        Input dataframe
    cols : list
        Numerical columns to check
    k : float
        IQR multiplier (default 1.5)

    Returns
    -------
    df_clean : pd.DataFrame
        DataFrame after dropping outliers
    bounds : dict
        Dictionary of lower & upper bounds per column
    """
    before_rows = df.shape[0]
    df_clean = df.copy()
    bounds = {}

    print(f"Total rows before: {before_rows}")

    for col in cols:
        Q1 = df_clean[col].quantile(0.25)
        Q3 = df_clean[col].quantile(0.75)
        IQR = Q3 - Q1

        lower = Q1 - k * IQR
        upper = Q3 + k * IQR
        bounds[col] = (lower, upper)

        before_col_rows = df_clean.shape[0]

        df_clean = df_clean[
            (df_clean[col] >= lower) &
            (df_clean[col] <= upper)
        ]

        after_col_rows = df_clean.shape[0]

        print(f"\nColumn: {col}")
        print(f"  IQR bounds : ({lower:.3f}, {upper:.3f})")
        print(f"  Rows before: {before_col_rows}")
        print(f"  Rows after : {after_col_rows}")
        print(f"  Dropped    : {before_col_rows - after_col_rows}")

    print("\n" + "-" * 40)
    print(f"Total rows after : {df_clean.shape[0]}")
    print(f"Total dropped    : {before_rows - df_clean.shape[0]}")
    print("-" * 40)

    return df_clean, bounds

