import scipy.stats as stats
import numpy as np

def best_fit_distribution(data, bins=50):
    """Pengecekan distribusi data menggunakan statistik"""
    data = data.dropna().values

    # histogram data
    y, x = np.histogram(data, bins=bins, density=True)
    x_mid = (x[:-1] + x[1:]) / 2

    distributions = [
        stats.norm,
        stats.lognorm,
        stats.expon,
        stats.gamma,
        stats.beta,
        stats.uniform
    ]

    best_dist = None
    best_params = None
    best_sse = np.inf

    for dist in distributions:
        try:
            params = dist.fit(data)
            pdf = dist.pdf(x_mid, *params)
            sse = np.sum((y - pdf) ** 2)

            if sse < best_sse:
                best_sse = sse
                best_dist = dist
                best_params = params
        except Exception:
            pass

    return best_dist.name, best_params, best_sse

# initialize
results = []

# jalankan fungsi
for col in num_cols:
    dist_name, params, sse = best_fit_distribution(df_train_eda[col])
    results.append({
        "feature": col,
        "best_distribution": dist_name,
        "sse": sse
    })

dist_df = pd.DataFrame(results)
dist_df

"""SSE = seberapa “melenceng” kurva distribusi teoritis dari distribusi data asli

- **Distribusi skewed & bounded**
  - FE: log transform, binning
  - Model: **non-linear** (tidak asumsi normal / linear)

- **Financial features (long-tail)**
  - FE: ratio, high-value flag
  - Model: **complex**, mampu menangkap interaction

- **Referrals (count, zero-heavy)**
  - FE: binary flag, bucket
  - Model: **non-linear**, bukan regresi linear count mentah

- **Tenure, Age, Churn Score**
  - FE: bucket + interaction
  - Model: **non-linear** (interaction-aware)

- **Location tidak uniform**
  - FE: clustering → region feature
  - Model: **complex**, bisa learn spatial pattern

**Kesimpulan:**  
Data **tidak cocok** untuk model linear sederhana.  
Perlu **model non-linear / complex** + FE eksplisit untuk interaction & skewness.
"""

# stats description
df_train_eda[num_cols].describe().T

"""- **Mean jauh > median + max ekstrem**
  → distribusi skewed / long-tail  
  → **tidak cocok asumsi linear**

- **25%–50% = 0 (zero-heavy)**
  → sinyal muncul di **ada vs tidak ada**  
  → linear lemah, butuh **split / non-linear behavior**

- **Std besar (≈ mean)**
  → variansi tidak stabil  
  → asumsi linear klasik gugur

- **Hanya sedikit fitur yang rapi & simetris**
  → sebagian fitur bisa linear  
  → **keseluruhan data tetap non-linear**

Kesimpulan
> **Data ini secara alami lebih cocok untuk model non-linear / kompleks.**  
> Model linear hanya masuk akal dengan FE berat (log, bin, interaction manual).
"""

