"""Semua kolom tidak mempunyai variance konstan

## Statistical Analysis
---

### Variance Inflation Factor (VIF)

Untuk setiap fitur \( X_j \), VIF didefinisikan sebagai:

![VIF Formula](https://latex.codecogs.com/svg.image?\text{VIF}_j=\frac{1}{1-R_j^2})

dengan:
- \( R_j^2 \): koefisien determinasi dari regresi  
  \( X_j \sim X_1, X_2, \dots, X_k \ (k \neq j) \)
- \( X_j \): fitur ke-\(j\) yang sedang diuji
"""

def compute_vif(X):
    vif_data = []

    for col in X.columns:
        # X_j sebagai target
        y = X[col]

        # fitur lain sebagai predictor
        X_others = X.drop(columns=[col])
        X_others = sm.add_constant(X_others)

        # regresi linear
        model = sm.OLS(y, X_others).fit()
        r_squared = model.rsquared

        # hitung VIF
        vif = 1 / (1 - r_squared)

        vif_data.append({
            "feature": col,
            "R_squared": r_squared,
            "VIF": vif
        })

    return pd.DataFrame(vif_data)

X = df_train_eda.select_dtypes(include=["int64", "float64"]).copy()
X = X.dropna()

# jalankan function
vif_df = compute_vif(X)
vif_df.sort_values("VIF", ascending=False)

