from scipy.stats import pointbiserialr

def numeric_vs_binary(
    df,
    numeric_cols,
    target_col,
    alpha=0.05
):
    """
    Point-Biserial correlation for numeric vs binary target

    Adds:
    - significant (p < alpha)
    - effect_size (weak / moderate / strong)
    - direction (higher in class 1 / class 0)
    """

    rows = []

    for col in numeric_cols:
        corr, p = pointbiserialr(df[target_col], df[col])

        # significance
        significant = p < alpha

        # effect size interpretation
        abs_corr = abs(corr)
        if abs_corr < 0.1:
            effect = "very weak"
        elif abs_corr < 0.3:
            effect = "weak"
        elif abs_corr < 0.5:
            effect = "moderate"
        else:
            effect = "strong"

        # direction
        if corr > 0:
            direction = "higher when target = 1"
        elif corr < 0:
            direction = "higher when target = 0"
        else:
            direction = "no difference"

        rows.append({
            "feature": col,
            "correlation": corr,
            "abs_corr": abs_corr,
            "p_value": p,
            "significant": significant,
            "effect_size": effect,
            "direction": direction
        })

    return (
        pd.DataFrame(rows)
        .sort_values("abs_corr", ascending=False)
        .reset_index(drop=True)
    )

numeric_vs_binary(df_train_eda, numeric_cols, 'Churn')

