from scipy.stats import chi2_contingency

def binary_vs_binary(
    df,
    binary_cols,
    target_col,
    alpha=0.05
):
    """
    Binary (categorical) vs Binary target analysis
    Uses Chi-Square test + Cramér's V

    Adds:
    - significant (p < alpha)
    - effect_size interpretation
    - interpretation text
    """

    rows = []

    for col in binary_cols:
        if col == target_col:
            continue

        ct = pd.crosstab(df[col], df[target_col])

        # chi-square test
        chi2, p_value, _, _ = chi2_contingency(ct)

        # cramér's v
        n = ct.sum().sum()
        v = np.sqrt(chi2 / (n * (min(ct.shape) - 1)))

        # significance
        significant = p_value < alpha

        # effect size interpretation
        if v < 0.1:
            effect = "very weak"
        elif v < 0.3:
            effect = "weak"
        elif v < 0.5:
            effect = "moderate"
        else:
            effect = "strong"

        # simple interpretation
        if not significant:
            insight = "no statistically significant association"
        else:
            insight = f"statistically significant ({effect} association)"

        rows.append({
            "feature": col,
            "cramers_v": v,
            "p_value": p_value,
            "significant": significant,
            "effect_size": effect,
            "interpretation": insight
        })

    return (
        pd.DataFrame(rows)
        .sort_values("cramers_v", ascending=False)
        .reset_index(drop=True)
    )

binary_vs_binary(df, binary_cols, 'Churn')

