# exclude code non relevant

DROP_PREFIXES = [
    # Aggregated charges (structural redundancy)
    "Total Charges",
    "Total Revenue",
    "Total Long Distance Charges",
    "Total Extra Data Charges",
    "Total Refunds",

    # Perfect dependency (keep Partner)
    "Married",

    # No structural churn signal
    "Population",
    "Avg Monthly Long Distance Charges",
    "Avg Monthly GB Download",

    # No meaningful association
    "Phone Service",
    "Gender",
]

KEEP_COLS_EXPLICIT = [
    "Partner",       # kept instead of Married
]


def exclude_columns_encoded(df: pd.DataFrame) -> pd.DataFrame:
    """Drop kolom dengan pola 'enc_'"""
    cols_to_drop = []

    # looping semua kolom
    for col in df.columns:
        for prefix in DROP_PREFIXES:
            if col.startswith(prefix):
                cols_to_drop.append(col)

    # Safety: ensure kept prefixes are NOT dropped
    for col in df.columns:
        for keep in KEEP_COLS_EXPLICIT:
            if col.startswith(keep) and col in cols_to_drop:
                cols_to_drop.remove(col)

    return df.drop(columns=cols_to_drop)

# jalankan fungsi
