def apply_tenure_binning(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy()
    df["Tenure_bucket"] = pd.cut(
        df["Tenure in Months"],
        bins=TENURE_BINS,
        labels=TENURE_LABELS,
        right=False
    )
