"""## Feature Selection
---

Feature selection cukup dilakukan dengan Logistic Regression karena ia adalah model linear yang menilai kontribusi tiap fitur secara langsung dan terpisah. Logistic Regression sangat sensitif terhadap fitur yang redundan, noisy, atau saling berkorelasi, sehingga forward/backward selection bisa benar-benar mengukur nilai murni sebuah fitur terhadap performa model. Metode seleksi ini memang berasal dari teori model linear (GLM) dan tidak valid bila diterapkan ke model non-linear seperti SVM kernel atau XGBoost yang menangkap interaksi kompleks secara implisit. Karena itu, fitur yang lolos di Logistic Regression umumnya aman dan stabil untuk dipakai oleh semua model lain, sementara proses seleksinya sendiri cukup dilakukan sekali pada model linear tersebut.
"""

def evaluate_features_lr(
    X_train,
    y_train,
    X_valid,
    y_valid,
    features,
    imbalance_strategy: str = "class_weight",
):
    """
    imbalance_strategy:
    - 'class_weight'  → LogisticRegression(class_weight='balanced')
    - 'sampling'  → LogisticRegression(class_weight=None)
    """

    if imbalance_strategy == "sampling":
        class_weight = None
    elif imbalance_strategy == "class_weight":
        class_weight = "balanced"
    else:
        raise ValueError(
            "imbalance_strategy must be 'class_weight' or 'oversampling'"
        )

    model = LogisticRegression(
        max_iter=1000,
        class_weight=class_weight,
        n_jobs=1,
    )

    model.fit(X_train[features], y_train)

    y_prob = model.predict_proba(X_valid[features])[:, 1]
    pr_auc = average_precision_score(y_valid, y_prob)

    return pr_auc

# list kolom
candidate_features = X_train.columns.tolist()

"""### Forward Base
---
"""

def forward_selection(
    X_train,
    y_train,
    X_valid,
    y_valid,
    candidate_features,
    min_improvement=0.001,
    imbalance_strategy="class_weight",
):
    selected_features = []
    best_score = 0.0

    while True:
        scores = []

        for f in candidate_features:
            if f in selected_features:
                continue

            trial_features = selected_features + [f]

            score = evaluate_features_lr(
                X_train, y_train,
                X_valid, y_valid,
                trial_features,
                imbalance_strategy=imbalance_strategy,
            )

            scores.append((f, score))

        if not scores:
            break

        best_feature, best_new_score = max(scores, key=lambda x: x[1])

        improvement = best_new_score - best_score

        if improvement < min_improvement:
            break

        selected_features.append(best_feature)
        best_score = best_new_score

        print(
            f"[FORWARD] + {best_feature} | PR AUC: {best_score:.4f}"
        )

    return selected_features

# run untuk model tanpa oversampling
