def retrain_and_evaluate(
    model_name: str,
    model,
    X_train,
    y_train,
    X_valid,
    y_valid,
    train_type: str,
    threshold: float = 0.5,
):
    """
    Re-train model and evaluate on TRAIN & VALID
    stage = re_training
    """

    start_time = time.perf_counter()

    # TRAIN
    model.fit(X_train, y_train)

    # TRAIN metrics
    train_metrics = evaluate_model(model, X_train, y_train, threshold)

    y_train_prob = model.predict_proba(X_train)[:, 1]
    y_train_pred = (y_train_prob >= threshold).astype(int)

    train_report_path = save_classification_report_image(
        y_true=y_train,
        y_pred=y_train_pred,
        model_name=model_name,
        train_type=train_type,
        stage="re_training_train",
    )

    # VALID
    valid_metrics = evaluate_model(model, X_valid, y_valid, threshold)

    y_valid_prob = model.predict_proba(X_valid)[:, 1]
    y_valid_pred = (y_valid_prob >= threshold).astype(int)

    valid_report_path = save_classification_report_image(
        y_true=y_valid,
        y_pred=y_valid_pred,
        model_name=model_name,
        train_type=train_type,
        stage="re_training_valid",
    )

    elapsed = time.perf_counter() - start_time

    log_payload = {
        "stage": "re_training",
        "train_type": train_type,
        "model": model_name,
        "time_sec": round(elapsed, 2),

        # TRAIN
        "train_recall": train_metrics["recall"],
        "train_pr_auc": train_metrics["pr_auc"],
        "train_roc_auc": train_metrics["roc_auc"],

        # VALID
        "valid_recall": valid_metrics["recall"],
        "valid_pr_auc": valid_metrics["pr_auc"],
        "valid_roc_auc": valid_metrics["roc_auc"],

        # GAP (OVERFITTING SIGNAL)
        "gap_pr_auc": train_metrics["pr_auc"] - valid_metrics["pr_auc"],
        "gap_roc_auc": train_metrics["roc_auc"] - valid_metrics["roc_auc"],

        # ARTIFACT
        "train_report_path": train_report_path,
        "valid_report_path": valid_report_path,
    }

    logger_re_train.info(log_payload)

    return model, log_payload

