def apply_binning(df):
    df = df.copy()

    df["Tenure_bucket"] = pd.cut(
        df["Tenure"],
        bins=TENURE_BINS,
        labels=TENURE_LABELS,
        include_lowest=True
    ).astype(int)

    df["Age_bucket"] = pd.cut(
        df["Age"],
        bins=AGE_BINS,
        labels=AGE_LABELS,
        include_lowest=True
    ).astype(int)

    return df

def inference_pipeline(raw_df, preprocess, model):
    df = raw_df.copy()

    # BINNING
    df = apply_binning(df)

    # LOG TRANSFORM
    for col in preprocess["log_cols"]:
        df[col] = np.log1p(df[col])

    # SCALING
    df[preprocess["cont_cols"]] = preprocess["scaler"].transform(
        df[preprocess["cont_cols"]]
    )

    # OHE + remainder
    X = preprocess["ohe_preprocess"].transform(df)

    # PREDICT
    proba = model.predict_proba(X)[:, 1]
    pred = (proba >= 0.5).astype(int)

    return pred, proba

